class Solution(object):
    def longestPalindrome(self, s, t):
        # Brute force: try all substrings of s and t, check if concat is palindrome
        def is_palindrome(x):
            return x == x[::-1]

        best = 1  # single char always works
        # Try all substrings of s alone and t alone
        for a in range(len(s) + 1):
            for b in range(a, len(s) + 1):
                sub = s[a:b]
                if sub and is_palindrome(sub):
                    best = max(best, len(sub))
        for a in range(len(t) + 1):
            for b in range(a, len(t) + 1):
                sub = t[a:b]
                if sub and is_palindrome(sub):
                    best = max(best, len(sub))
        # Try all pairs of substrings
        for i in range(len(s) + 1):
            for j in range(i, len(s) + 1):
                sub_s = s[i:j]
                for p in range(len(t) + 1):
                    for q in range(p, len(t) + 1):
                        sub_t = t[p:q]
                        if sub_s or sub_t:
                            concat = sub_s + sub_t
                            if is_palindrome(concat):
                                best = max(best, len(concat))
        return best
